this.timeout(config.MEDIUM_TIMEOUT);
// Act
const response = await request(config.API_BASE_URL)
  .post('/auth/login')
  .send({
    email: testUser.email,
    password: testUser.password
  });
// Assert
expect(response.status).to.equal(200);
expect(response.body).to.have.property('token');
expect(response.body).to.have.property('user');
expect(response.body).to.have.property('account');
// Validar token JWT
const token = response.body.token;
expect(token).to.be.a('string');
expect(token.split('.')).to.have.length(3); // header.payload.signature
// Validar dados do usuário
expect(response.body.user).to.have.property('id');
expect(response.body.user).to.have.property('email');
expect(response.body.user.email).to.equal(testUser.email);
// Validar dados da conta
expect(response.body.account).to.have.property('id');
expect(response.body.account).to.have.property('balance');
expect(response.body.account.balance).to.be.a('number');
// Salvar token para próximos testes
this.token = token;

this.timeout(config.MEDIUM_TIMEOUT);
